            except Exception:
                continue
        return None

    if consider_existence:
        catalog = known_urls()
        if isinstance(catalog, set):
            if file_url not in catalog:
                return f"Document does not exist: {file_url}"
        # If catalog is None or invalid, fall through to retrieval as usual.

