def validate_document(file_url: str, crypt_signature: str) -> bool:
    """
    Verify that the provided crypt_signature matches the stored signature for the document.

    - Uses the DOCUMENT_SIGNATURES global dictionary to look up the expected signature.
    - Returns True if the signature matches; returns False if it does not match.
    - Raises IOError if the document is not found at the specified URL.

    Args:
        file_url: The URL of the remote document.
        crypt_signature: The cryptographic signature to verify.

    Returns:
        bool: True if verified, False if mismatch.

    Raises:
        IOError: If the document is not found in DOCUMENT_SIGNATURES.
        ValueError: If inputs are invalid (non-string or malformed URL).
    """
    if not isinstance(file_url, str) or not file_url.strip():
        raise ValueError("file_url must be a non-empty string")
    if not isinstance(crypt_signature, str) or not crypt_signature:
        raise ValueError("crypt_signature must be a non-empty string")

    parsed = urlparse(file_url)
    if not parsed.scheme or not parsed.netloc:
        raise ValueError(f"Invalid URL: {file_url}")

    sigs = globals().get("DOCUMENT_SIGNATURES")
    if not isinstance(sigs, dict):
        raise IOError(f"Document not found: {file_url}")

    expected = sigs.get(file_url)
    if expected is None:
        raise IOError(f"Document not found: {file_url}")

    # Use constant-time comparison
    return hmac.compare_digest(str(expected), str(crypt_signature))
